// A simple Playwright test example
import { test, expect } from '@playwright/test';

test('basic navigation test', async ({ page }) => {
  // Navigate to a website
  await page.goto('https://playwright.dev');

  // Click on a link
  await page.click('text=Get Started');

  // Verify we're on the right page
  await expect(page).toHaveURL(/.*intro/);

  // Check for specific text on the page
  await expect(page.locator('h1')).toContainText('Installation');
});

// That's it! Notice:
// - No explicit waits needed
// - Clean, readable syntax
// - Built-in assertions with expect()

// Testing a login flow - a common real-world scenario
import { test, expect } from '@playwright/test';

test('user can login successfully', async ({ page }) => {
  // Navigate to login page
  await page.goto('https://example.com/login');

  // Fill in credentials
  await page.fill('input[name="email"]', 'user@example.com');
  await page.fill('input[name="password"]', 'securePassword123');

  // Click login button
  await page.click('button[type="submit"]');

  // Wait for navigation and verify success
  await expect(page).toHaveURL('https://example.com/dashboard');
  await expect(page.locator('.welcome-message')).toBeVisible();
  await expect(page.locator('.user-name')).toContainText('Welcome back!');
});

// Key points:
// - Playwright automatically waits for navigation after clicking submit
// - We can chain multiple assertions
// - The test is easy to read and understand
